/* ── SVG Filters ── */
function PaperFilters() {
  return (
    <svg width="0" height="0" style={{ position: "absolute" }}>
      <defs>
        <filter id="roughEdge" x="-5%" y="-5%" width="110%" height="110%">
          <feTurbulence type="turbulence" baseFrequency="0.012" numOctaves="4" seed="2" result="noise" />
          <feDisplacementMap in="SourceGraphic" in2="noise" scale="6" xChannelSelector="R" yChannelSelector="G" />
        </filter>
        <filter id="paperGrain" x="0%" y="0%" width="100%" height="100%">
          <feTurbulence type="fractalNoise" baseFrequency="0.65" numOctaves="5" stitchTiles="stitch" result="grain" />
          <feColorMatrix type="saturate" values="0" in="grain" result="grainBW" />
          <feBlend in="SourceGraphic" in2="grainBW" mode="multiply" />
        </filter>
      </defs>
    </svg>
  );
}

/* ── Full-size Question Card ── */
